#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__kernel void dynproc_kernel(
    int pyramid_height,
    __global int* d_gpuWall,
    __global int* d_gpuResult_src,
    __global int* d_gpuResult_dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* d_outputBuffer
)
{
    int n = get_global_id(0);

    if (n >= cols) return;

    // Get current value from source buffer
    int current = d_gpuResult_src[n];

    // Get min from three adjacent positions (above, above-left, above-right)
    int min = current;
    if (n > 0)
        min = MIN(min, d_gpuResult_src[n-1]);
    if (n < cols-1)
        min = MIN(min, d_gpuResult_src[n+1]);

    // Add wall value for the next row
    // d_gpuWall starts from wall[1], so wall[t+1][n] = d_gpuWall[t*cols + n]
    int wall_idx = t * cols + n;
    int result = d_gpuWall[wall_idx] + min;

    // Write result to destination buffer
    d_gpuResult_dst[n] = result;
}
